INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-792a7dff-moex-00089', 'judicial-792a7dff', 'judicial-792a7dff-moex-111-69fcaee1', 'sub-judicial-792a7dff-03', NULL, 'essay', '甲在火鍋店吃火鍋時，看到素有嫌隙的乙在隔壁桌用餐，即向乙口出「垃
圾」、「廢物」等語用以洩憤，乙被刺激到受不了，站起來以拳頭揮向甲
的臉部。甲雖非刻意引起攻擊，但也早有防備，儘管尚有閃避的空間，
仍在乙拳頭即將擊中前，出腳踹向乙的大腿，使乙跌倒在地，造成其多
處挫傷。請問甲之刑事責任如何？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:57+00:00", "source_pdf_sha1": "9e881b074565", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "106", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法與刑法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL),
  ('judicial-792a7dff-moex-00090', 'judicial-792a7dff', 'judicial-792a7dff-moex-111-69fcaee1', 'sub-judicial-792a7dff-03', NULL, 'essay', '駕駛大卡車的甲，不滿小客車駕駛乙按鳴喇叭，多次急切到乙之車道前
方後再急煞車，且一再貼近乙車後方、側面逼車，好幾次都差點碰撞到
乙車。行駛數公里後，乙因害怕而停車與甲爭吵，一名路人丙見狀，上
前謊稱自己是便衣交通警察，欲調查此件行車糾紛，要求甲、乙提供證
件以查驗身分，二人從之。請問甲、丙之刑事責任如何？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:57+00:00", "source_pdf_sha1": "9e881b074565", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "106", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法與刑法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL),
  ('judicial-792a7dff-moex-00091', 'judicial-792a7dff', 'judicial-792a7dff-moex-111-3d2b73b6', 'sub-judicial-792a7dff-09', NULL, 'single_choice', '依司法院大法官解釋，下列何者尚不違背法治國家正當法律程序之要求？', '["以行政文書依法寄存送達完畢時，作為發生送達效力之時點", "稽徵稅捐所發之各種文書，規定對公同共有人中之一人為送達者，其效力及於全體", "於自辦市地重劃案件，未設置適當組織，以審議關於市地重劃範圍之核定程序", "於都市更新程序，未確保利害關係人知悉相關資訊及適時陳述意見之機會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:57+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "106", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL),
  ('judicial-792a7dff-moex-00092', 'judicial-792a7dff', 'judicial-792a7dff-moex-111-3d2b73b6', 'sub-judicial-792a7dff-09', NULL, 'single_choice', '依憲法增修條文規定，下列何者有權提出憲法修正案？', '["自由地區選舉人連署", "國民大會", "總統", "立法院"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:57+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "106", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL),
  ('judicial-792a7dff-moex-00093', 'judicial-792a7dff', 'judicial-792a7dff-moex-111-3d2b73b6', 'sub-judicial-792a7dff-09', NULL, 'single_choice', '依司法院釋字第609號解釋意旨，有關勞工保險，下列敘述何者正確？', '["勞工保險應謹守對價原則，以符合保險契約之本質", "勞工保險與商業保險相同，應由勞工保險局評估危險後決定是否簽訂保險契約", "勞工保險得由勞工保險局與被保險人自由約定保險契約，排除勞工保險條例的適用", "勞工保險條例之排除保險給付規定，得由立法機關依保險法理並參酌其他社會安全制度形成之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:57+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "106", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL),
  ('judicial-792a7dff-moex-00094', 'judicial-792a7dff', 'judicial-792a7dff-moex-111-3d2b73b6', 'sub-judicial-792a7dff-09', NULL, 'single_choice', '關於刑法撤銷假釋之規定與人身自由之關係，下列敘述何者正確？', '["撤銷假釋之規定，對受假釋人之人身自由造成限制，故不得再執行殘刑", "撤銷假釋之規定，限制受假釋人之人身自由，屬憲法保留事項，故不得以法律定之", "撤銷假釋之規定，對受假釋人之人身自由造成限制，必須符合比例原則之要求", "撤銷假釋之規定，並未使受假釋人承受新刑罰，故並未限制受假釋人之人身自由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:57+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "106", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL),
  ('judicial-792a7dff-moex-00095', 'judicial-792a7dff', 'judicial-792a7dff-moex-111-3d2b73b6', 'sub-judicial-792a7dff-09', NULL, 'single_choice', '依司法院大法官解釋，有關婚姻與家庭之保障，下列敘述何者錯誤？', '["婚姻與家庭制度應受制度性保障", "家庭制度之保障植根於人格自由", "人民收養子女之自由為憲法第22條所保障", "限制人民收養其配偶之大陸地區子女為違反平等權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:57+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "106", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL),
  ('judicial-792a7dff-moex-00096', 'judicial-792a7dff', 'judicial-792a7dff-moex-111-3d2b73b6', 'sub-judicial-792a7dff-09', NULL, 'single_choice', '中央警察大學研究所碩士班入學考試招生簡章，以有無色盲決定能否取得入學資格之規定，依司法院釋字 第626號解釋，下列敘述何者錯誤？', '["相關入學資格條件之設定，為大學自治事項，於合理及必要之範圍內，不生違反法律保留之問題", "受國民教育以外教育之權利雖受憲法第22條所保障，但不包括賦予人民請求給予入學許可之權利", "警大自治權之行使，應受其功能本質之限制，且為確保其達成國家賦予之政策功能，而應接受比一般大 學更多之國家監督", "鑑於色盲非屬人力所得控制之生理缺陷，警察大學作為培養國家警察專門人才之學術單位，自不得以此 作為差別待遇標準"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:57+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "106", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL),
  ('judicial-792a7dff-moex-00097', 'judicial-792a7dff', 'judicial-792a7dff-moex-111-3d2b73b6', 'sub-judicial-792a7dff-09', NULL, 'single_choice', '法律規定汽車駕駛人駕車強行闖越鐵路平交道，因而肇事者，處新臺幣1萬5千元以上9萬元以下罰鍰， 並吊銷其駕駛執照，終身不得考領駕駛執照，並應接受道路交通安全講習。關於上開規定，依司法院釋字 第780號解釋，下列敘述何者錯誤？', '["處以罰鍰係對汽車駕駛人財產權之限制", "終身不得考領駕駛執照，係限制汽車駕駛人之一般行為自由", "如駕駛人為職業駕駛人，則吊銷其駕駛執照將涉及人民選擇職業自由之客觀條件限制", "強制駕駛人參加道路交通安全講習，係對人民一般行為自由之限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:57+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "106", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL),
  ('judicial-792a7dff-moex-00098', 'judicial-792a7dff', 'judicial-792a7dff-moex-111-3d2b73b6', 'sub-judicial-792a7dff-09', NULL, 'single_choice', '有關憲法第22條所稱「其他權利」，下列敘述何者正確？', '["「不妨礙社會秩序公共利益」應遵循社會多數意見作解釋", "本條之基本權利位階及效力較其他基本權劣後", "大法官依據本條而導出新聞自由之保障", "本條會隨著時代及社會的發展而進展"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:57+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "106", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL)
